query:
SET @security_id = (SELECT id FROM courses WHERE title = 'Segurança & Compliance' LIMIT 1);

-- Atualizar todas as aulas de Segurança com vídeos
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/jIKdtALRdKE' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id) AND title = 'Princípios de Segurança';
