UPDATE lessons SET video_url = 'https://www.youtube.com/embed/f8ZqAe3k8N4' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id) AND title = 'Hash e Assinatura Digital';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/2nnIHHLvf00' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id) AND title = 'OAuth e OpenID Connect';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/JBNUlU_jsqM' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id) AND title = 'JWT e Tokens';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/K8LJVjkv6Ow' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id) AND title = 'LGPD e Privacidade';

SELECT COUNT(*) as security_videos FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id) AND video_url IS NOT NULL;

